/* ── Single Tree Predict ── */
static inline int _tree_predict(
    const int8_t *feat, const float *thr,
    const int16_t *left, const int16_t *right,
    const int8_t *val, const float *x)
{
    int n = 0;
    while (feat[n] >= 0)
        n = (x[feat[n]] <= thr[n]) ? left[n] : right[n];
    return val[n];
}

