/* ── Class Name Helper ── */
static inline const char *class_name(int c)
{
    switch (c)
    {
    case 0:
        return "detergent";
    case 1:
        return "detergent_water";
    case 2:
        return "extreme_diluted";
    case 3:
        return "pure_milk";
    case 4:
        return "starch";
    case 5:
        return "starch_detergent";
    case 6:
        return "starch_detergent_diluted";
    case 7:
        return "starch_diluted";
    case 8:
        return "water_added";
    default:
        return "Unknown";
    }
}

